wrong_code:
// WRONG — assumes token is slot 0 and owner is slot 1
// breaks immediately if storage layout changes
assembly {
    let tokenAddr := sload(0)  // fragile
    let ownerAddr := sload(1)  // fragile
}

correct_code:
// CORRECT option A — use Solidity's .slot syntax in inline assembly
// valid when the variable is in scope
assembly {
    let tokenAddr := sload(token.slot)
    let ownerAddr := sload(owner.slot)
}

// CORRECT option B — for immutables, use immutable keyword
// saves 200+ gas per read vs storage
address public immutable token;
address public immutable owner;
// Then in assembly: no sload needed, reads from bytecode directly

immutable_example:
// Most gas efficient for addresses set in constructor
contract SimpleVault {
    address public immutable token;  // reads from bytecode, not storage
    address public immutable owner;

    constructor(address _token) {
        token = _token;
        owner = msg.sender;
    }
    // In assembly: no sload() needed at all
}
